from pathlib import Path
import sqlite3

DB=Path(__file__).resolve().parents[1]/"prisma"/"dev.db"
DDL="""
PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS User (id TEXT PRIMARY KEY,name TEXT NOT NULL DEFAULT '管理者',createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS CompanySetting (id INTEGER PRIMARY KEY DEFAULT 1,companyName TEXT NOT NULL DEFAULT '',tradeName TEXT,representativeName TEXT,postalCode TEXT,address TEXT,phone TEXT,fax TEXT,email TEXT,invoiceNumber TEXT,bankName TEXT,bankBranch TEXT,accountType TEXT,accountNumber TEXT,accountHolder TEXT,constructionLicense TEXT,logoPath TEXT,sealPath TEXT,defaultValidityDays INTEGER NOT NULL DEFAULT 30,defaultTaxRate DECIMAL NOT NULL DEFAULT 0.1,updatedAt DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS AppSetting (key TEXT PRIMARY KEY,value TEXT NOT NULL,updatedAt DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS Project (id TEXT PRIMARY KEY,projectName TEXT NOT NULL,constructionName TEXT,customerName TEXT NOT NULL,customerAddress TEXT,siteAddress TEXT NOT NULL,phone TEXT,estimateDate DATETIME,estimatedPeriod TEXT,personInCharge TEXT,projectType TEXT NOT NULL DEFAULT '戸建',notes TEXT,createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updatedAt DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS ProjectMeasurement (id TEXT PRIMARY KEY,projectId TEXT NOT NULL UNIQUE,deductionMethod TEXT NOT NULL DEFAULT 'RATE',valuesJson TEXT NOT NULL DEFAULT '{}',calculatedJson TEXT NOT NULL DEFAULT '{}',updatedAt DATETIME NOT NULL,FOREIGN KEY(projectId) REFERENCES Project(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS ProjectOpening (id TEXT PRIMARY KEY,projectId TEXT NOT NULL,name TEXT NOT NULL,direction TEXT NOT NULL,width DECIMAL NOT NULL,height DECIMAL NOT NULL,quantity INTEGER NOT NULL DEFAULT 1,area DECIMAL NOT NULL,notes TEXT,FOREIGN KEY(projectId) REFERENCES Project(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS WorkCategory (id TEXT PRIMARY KEY,code TEXT NOT NULL UNIQUE,name TEXT NOT NULL,displayOrder INTEGER NOT NULL DEFAULT 0,active BOOLEAN NOT NULL DEFAULT 1);
CREATE TABLE IF NOT EXISTS QuantitySourceMaster (id TEXT PRIMARY KEY,code TEXT NOT NULL UNIQUE,displayName TEXT NOT NULL,unit TEXT NOT NULL,active BOOLEAN NOT NULL DEFAULT 1);
CREATE TABLE IF NOT EXISTS WorkItemMaster (id TEXT PRIMARY KEY,itemCode TEXT NOT NULL UNIQUE,displayName TEXT NOT NULL,categoryId TEXT NOT NULL,unit TEXT NOT NULL,standardSalesPrice DECIMAL NOT NULL DEFAULT 0,standardCost DECIMAL NOT NULL DEFAULT 0,defaultQuantitySource TEXT,quantityCandidatesJson TEXT NOT NULL DEFAULT '[]',displayOrder INTEGER NOT NULL DEFAULT 0,active BOOLEAN NOT NULL DEFAULT 1,notes TEXT,FOREIGN KEY(categoryId) REFERENCES WorkCategory(id));
CREATE TABLE IF NOT EXISTS PricePattern (id TEXT PRIMARY KEY,name TEXT NOT NULL UNIQUE,notes TEXT,createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updatedAt DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS PricePatternItem (id TEXT PRIMARY KEY,patternId TEXT NOT NULL,workItemId TEXT NOT NULL,salesPrice DECIMAL NOT NULL,costPrice DECIMAL,UNIQUE(patternId,workItemId),FOREIGN KEY(patternId) REFERENCES PricePattern(id) ON DELETE CASCADE,FOREIGN KEY(workItemId) REFERENCES WorkItemMaster(id));
CREATE TABLE IF NOT EXISTS Estimate (id TEXT PRIMARY KEY,projectId TEXT NOT NULL,estimateName TEXT NOT NULL,estimateNumber TEXT NOT NULL UNIQUE,issueDate DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,validUntil DATETIME,status TEXT NOT NULL DEFAULT '下書き',version INTEGER NOT NULL DEFAULT 1,copiedFromId TEXT,changeReason TEXT,changedBy TEXT NOT NULL DEFAULT '管理者',notes TEXT,subtotal DECIMAL NOT NULL DEFAULT 0,discount DECIMAL NOT NULL DEFAULT 0,taxRate DECIMAL NOT NULL DEFAULT 0.1,taxAmount DECIMAL NOT NULL DEFAULT 0,totalAmount DECIMAL NOT NULL DEFAULT 0,confirmedAt DATETIME,createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updatedAt DATETIME NOT NULL,FOREIGN KEY(projectId) REFERENCES Project(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS EstimateVersion (id TEXT PRIMARY KEY,estimateId TEXT NOT NULL,version INTEGER NOT NULL,snapshotJson TEXT NOT NULL,changeReason TEXT,changedBy TEXT NOT NULL,previousAmount DECIMAL,newAmount DECIMAL NOT NULL,confirmedAt DATETIME,createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(estimateId) REFERENCES Estimate(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS EstimateItem (id TEXT PRIMARY KEY,estimateId TEXT NOT NULL,displayOrder INTEGER NOT NULL,level INTEGER NOT NULL DEFAULT 0,rowType TEXT NOT NULL DEFAULT 'NORMAL',workItemId TEXT,itemCodeSnapshot TEXT,nameSnapshot TEXT NOT NULL,specification TEXT,quantitySourceSnapshot TEXT,autoQuantity DECIMAL,manualQuantity DECIMAL,unitSnapshot TEXT NOT NULL,standardPriceSnapshot DECIMAL NOT NULL DEFAULT 0,manualPrice DECIMAL,costPrice DECIMAL NOT NULL DEFAULT 0,materialCost DECIMAL NOT NULL DEFAULT 0,subcontractCost DECIMAL NOT NULL DEFAULT 0,otherCost DECIMAL NOT NULL DEFAULT 0,notes TEXT,isFreeInput BOOLEAN NOT NULL DEFAULT 0,FOREIGN KEY(estimateId) REFERENCES Estimate(id) ON DELETE CASCADE,FOREIGN KEY(workItemId) REFERENCES WorkItemMaster(id));
CREATE TABLE IF NOT EXISTS Material (id TEXT PRIMARY KEY,name TEXT NOT NULL,standardCoverage DECIMAL NOT NULL,containerSize DECIMAL NOT NULL,coats INTEGER NOT NULL DEFAULT 1,lossRate DECIMAL NOT NULL DEFAULT 0,active BOOLEAN NOT NULL DEFAULT 1);
CREATE TABLE IF NOT EXISTS EstimateMaterial (id TEXT PRIMARY KEY,estimateId TEXT NOT NULL,materialName TEXT NOT NULL,targetArea DECIMAL NOT NULL,coverage DECIMAL NOT NULL,containerSize DECIMAL NOT NULL,coats INTEGER NOT NULL,lossRate DECIMAL NOT NULL,requiredAmount DECIMAL NOT NULL,requiredCans INTEGER NOT NULL,FOREIGN KEY(estimateId) REFERENCES Estimate(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS ContractSnapshot (id TEXT PRIMARY KEY,estimateId TEXT NOT NULL,snapshotJson TEXT NOT NULL,contractType TEXT NOT NULL DEFAULT '本契約',confirmedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(estimateId) REFERENCES Estimate(id));
CREATE TABLE IF NOT EXISTS ExportLog (id TEXT PRIMARY KEY,estimateId TEXT NOT NULL,format TEXT NOT NULL,filePath TEXT NOT NULL,success BOOLEAN NOT NULL,error TEXT,createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS OperationLog (id TEXT PRIMARY KEY,userId TEXT,targetType TEXT NOT NULL,targetId TEXT NOT NULL,action TEXT NOT NULL,beforeJson TEXT,afterJson TEXT,createdAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(userId) REFERENCES User(id));
"""
with sqlite3.connect(DB) as db: db.executescript(DDL)
print(DB)
